{
  "name": "Planejamento Mensal Pro",
  "description": "Uma ferramenta profissional para professores criarem e exportarem planos de aula mensais em formato PDF, com auxílio de IA para sugestão de conteúdos pedagógicos.",
  "requestFramePermissions": []
}

export interface PlanningRow {
  id: string;
  unidadeTematica: string;
  habilidades: string;
  estrategias: string;
  recursos: string;
  avaliacao: string;
  adaptacao: string;
}

export interface PlanningData {
  unidadeEscolar: string;
  professor: string;
  mes: string;
  anoTurma: string;
  observacoes: string;
  rows: PlanningRow[];
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const suggestEducationalContent = async (unidadeTematica: string) => {
  if (!unidadeTematica) return null;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Com base na unidade temática "${unidadeTematica}", sugira habilidades (BNCC), estratégias metodológicas, recursos, métodos de avaliação e adaptações curriculares. Retorne em formato JSON estruturado.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            habilidades: { type: Type.STRING },
            estrategias: { type: Type.STRING },
            recursos: { type: Type.STRING },
            avaliacao: { type: Type.STRING },
            adaptacao: { type: Type.STRING },
          },
          required: ["habilidades", "estrategias", "recursos", "avaliacao", "adaptacao"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Error:", error);
    return null;
  }
};

import React, { useState, useRef } from 'react';
import { PlanningData, PlanningRow } from './types';
import { suggestEducationalContent } from './services/geminiService';
import { 
  PlusIcon, 
  TrashIcon, 
  PrinterIcon, 
  SparklesIcon, 
  ArrowDownTrayIcon,
  ChevronDoubleDownIcon
} from '@heroicons/react/24/outline';

const App: React.FC = () => {
