    setData(prev => ({ ...prev, [field]: value }));
  };

  const handleRowChange = (id: string, field: keyof PlanningRow, value: string) => {
    setData(prev => ({
      ...prev,
      rows: prev.rows.map(row => row.id === id ? { ...row, [field]: value } : row)
    }));
  };

  const addRow = () => {
    setData(prev => ({
      ...prev,
      rows: [...prev.rows, {
        id: Math.random().toString(36).substr(2, 9),
        unidadeTematica: '',
        habilidades: '',
        estrategias: '',
        recursos: '',
        avaliacao: '',
        adaptacao: ''
      }]
    }));
  };

  const removeRow = (id: string) => {
    if (data.rows.length === 1) return;
    setData(prev => ({
      ...prev,
      rows: prev.rows.filter(row => row.id !== id)
    }));
  };

  const handleAiSuggest = async (id: string, tema: string) => {
    if (!tema) {
      alert("Por favor, preencha a 'Unidade Temática' antes de usar a IA.");
      return;
    }
    setIsAiLoading(id);
    const suggestions = await suggestEducationalContent(tema);
    if (suggestions) {
      setData(prev => ({
        ...prev,
        rows: prev.rows.map(row => row.id === id ? { 
          ...row, 
          habilidades: suggestions.habilidades,
          estrategias: suggestions.estrategias,
          recursos: suggestions.recursos,
          avaliacao: suggestions.avaliacao,
          adaptacao: suggestions.adaptacao
        } : row)
      }));
    }
    setIsAiLoading(null);
  };

