        <div className="flex flex-col gap-6 mb-8">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
               {/* Logo Placeholder */}
               <div className="w-20 h-20 bg-emerald-100 rounded-full border-2 border-emerald-600 flex items-center justify-center overflow-hidden">
                 <img src="https://picsum.photos/seed/edu/100/100" alt="Logo" className="w-full h-full object-cover" />
               </div>
               <h2 className="text-3xl font-bold text-emerald-800 tracking-tight uppercase">Planejamento Mensal</h2>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
