                <th className="border border-slate-800 p-2 text-xs uppercase w-[16.6%]">Recursos</th>
                <th className="border border-slate-800 p-2 text-xs uppercase w-[16.6%]">Avaliação</th>
                <th className="border border-slate-800 p-2 text-xs uppercase w-[16.6%]">Adaptação Curricular</th>
