                      </button>
                    </div>
                  </td>
                  <td className="border border-slate-800 p-0 align-top">
                    <textarea 
                      className="w-full h-full min-h-[150px] p-2 resize-none outline-none text-sm leading-relaxed"
                      value={row.habilidades}
                      onChange={(e) => handleRowChange(row.id, 'habilidades', e.target.value)}
