                    <button 
                      onClick={() => removeRow(row.id)}
                      className="no-print absolute -right-10 top-2 p-1.5 text-slate-400 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
                    >
                      <TrashIcon className="w-5 h-5" />
                    </button>
