          className="p-3 bg-white text-slate-600 rounded-full shadow-lg border border-slate-200 hover:bg-slate-50 transition-all active:scale-90"
          title="Voltar ao topo"
        >
          <ChevronDoubleDownIcon className="w-6 h-6 rotate-180" />
