          <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-4 text-sm bg-white p-4 rounded-lg border border-slate-200 print:border-none print:p-0">
            <div className="flex flex-col gap-1">
              <label className="font-bold text-slate-500 uppercase text-[10px] tracking-wider">Unidade Escolar</label>
              <input 
                type="text" 
                value={data.unidadeEscolar}
                onChange={(e) => handleInputChange('unidadeEscolar', e.target.value)}
                placeholder="Nome da Escola"
                className="border-b-2 border-slate-200 focus:border-emerald-500 outline-none py-1 font-medium text-slate-800 transition-colors print:border-slate-800"
              />
            </div>
            <div className="flex flex-col gap-1">
              <label className="font-bold text-slate-500 uppercase text-[10px] tracking-wider">Professor(a) / Agentes</label>
              <input 
                type="text" 
                value={data.professor}
                onChange={(e) => handleInputChange('professor', e.target.value)}
                placeholder="Nome do(a) Professor(a)"
                className="border-b-2 border-slate-200 focus:border-emerald-500 outline-none py-1 font-medium text-slate-800 transition-colors print:border-slate-800"
              />
