            <div className="flex flex-col gap-1">
              <div className="text-[9px] text-slate-500 font-bold uppercase tracking-tighter">
                Documento gerado em: {new Date().toLocaleDateString('pt-BR')}
              </div>
            </div>
            <div className="flex gap-12">
              <div className="flex flex-col items-center">
                <div className="w-56 border-b-2 border-slate-900 mb-2"></div>
                <span className="text-[10px] font-black uppercase text-slate-900 tracking-tighter italic">Professor(a) Responsável</span>
              </div>
              <div className="flex flex-col items-center">
                <div className="w-56 border-b-2 border-slate-900 mb-2"></div>
                <span className="text-[10px] font-black uppercase text-slate-900 tracking-tighter italic">Coordenação / Direção</span>
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* Botão de Topo */}
      <div className="no-print fixed bottom-8 right-8 flex flex-col gap-4">
        <button 
          onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
          className="p-4 bg-slate-900 text-white rounded-full shadow-2xl hover:bg-black transition-all active:scale-90 border-2 border-white"
        >
          <ChevronDoubleDownIcon className="w-6 h-6 rotate-180" />
        </button>
      </div>
    </div>
  );
};

