    const textOutput = response.text;

    if (typeof textOutput === 'string') {
      return JSON.parse(textOutput);
    }

    console.warn("IA retornou conteúdo vazio ou inválido.");
    return null;

  } catch (error) {
    console.error("Erro na chamada do Gemini:", error);
    return null;
  }
};

