            <div className="flex flex-col">
              <h1 className="text-lg font-black uppercase leading-none">Planejamento Mensal</h1>
              <p className="text-[8px] font-bold text-slate-600 uppercase">Prefeitura Municipal de Hortolândia - Secretaria de Educação</p>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-x-12 gap-y-3 text-[10px]">
            <div className="border-b border-slate-300 pb-1">
              <span className="font-black uppercase text-[8px] block text-slate-500">Unidade Escolar</span>
              <span className="font-bold">{data.unidadeEscolar || "..."}</span>
            </div>
            <div className="border-b border-slate-300 pb-1">
              <span className="font-black uppercase text-[8px] block text-slate-500">Professor(a) / Agentes</span>
              <span className="font-bold">{data.professor || "..."}</span>
            </div>
            <div className="border-b border-slate-300 pb-1">
              <span className="font-black uppercase text-[8px] block text-slate-500">Período (Mês / Ano)</span>
              <span className="font-bold">{data.mes || "..."}</span>
            </div>
            <div className="border-b border-slate-300 pb-1">
