    let current = row.habilidades;
    if (current.includes(skillText)) {
      current = current.replace(skillText, '').replace(/\n\n+/g, '\n').trim();
    } else {
      current = current ? `${current}\n\n${skillText}` : skillText;
    }
    handleRowChange(rowId, 'habilidades', current);
  };

