            </div>
            <div className="border-b border-slate-300 pb-1">
              <span className="font-black uppercase text-[8px] text-slate-500">Professor(a) / Agentes</span>
              <div className="font-bold">{data.professor || "..."}</div>
            </div>
            <div className="border-b border-slate-300 pb-1">
